template-STD_REG.scripts:
							function Set_Codigo_Seguridad()
{
if(Ctrl('oi_ubicacion').GetXValue()!='')
	{
	var emp = Ctrl('oi_empresa').GetXValue();
	var suc = Ctrl('oi_ubicacion').GetXValue();
	Ctrl('c_seguridad').SetXValue('UBI-'+emp+'-'+suc);
	Ctrl('d_usuario').SetXValue(Ctrl('oi_usuario_sys').GetCValue());
	}
return false;
}

qry:select.qry:xquery:
					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  LEG58_SEGURIDAD.oi_leg_seg as ID,
  LEG58_SEGURIDAD.oi_leg_seg as COD,
  LEG58_SEGURIDAD.oi_leg_seg as DES
from
  LEG58_SEGURIDAD
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

for $r in SQL(' {%? (#FILTER:@LEN='') {% %} {% maxsize {%=#FILTER:@LEN %} %} %}
SELECT
SEG.oi_leg_seg as ID, EMP.c_empresa as empresa, SUC.c_ubicacion as sucursal, EMP.d_empresa, SUC.d_ubicacion, SEG.d_usuario
FROM LEG58_SEGURIDAD as SEG, ORG03_EMPRESAS as EMP, ORG03_UBICACIONES as SUC
JOIN SEG.oi_empresa INNER EMP.oi_empresa, SEG.oi_ubicacion INNER SUC.oi_ubicacion
WHERE isNotNUll(SEG.oi_empresa) and isNotNull(SEG.oi_ubicacion)
{%?($FILTER/@search!='') {% and (contain(ucase(SUC.d_ubicacion),{upper-case($FILTER/@search)}) or contain(ucase(EMP.c_empresa),{upper-case($FILTER/@search)}) or contain(ucase(SUC.c_ubicacion),{upper-case($FILTER/@search)}) or contain(ucase(EMP.d_empresa),{upper-case($FILTER/@search)}) or contain(ucase(SEG.d_usuario),{upper-case($FILTER/@search)})) %} {% %} %}
{%?($FILTER/@order!='') {% order by {%=$FILTER/@order %} {%=iif($FILTER/@asc='1','asc','desc') %} %} {% %} %}
')/ROWS/ROW
